-- 1. Link tracks -> artists (the CSV's track_artist is a per-track attribute).
ALTER TABLE tracks ADD COLUMN IF NOT EXISTS artist_id BIGINT REFERENCES artists(id);
CREATE INDEX IF NOT EXISTS idx_tracks_artist_id ON tracks (artist_id);

-- 2. Stage the raw CSV rows. ON COMMIT DROP removes the table when Flyway commits this migration
CREATE TEMP TABLE spotify_import_raw (
    playlist_genre           TEXT    NOT NULL,
    track_artist             TEXT    NOT NULL,
    track_album_name         TEXT    NOT NULL,
    track_id                 TEXT    NOT NULL,
    track_name               TEXT    NOT NULL,
    track_album_release_date TEXT    NOT NULL,
    track_album_id           TEXT    NOT NULL,
    duration_ms              INTEGER NOT NULL
) ON COMMIT DROP;

