-- 3. Artists, de-duplicated by name (artists.name is UNIQUE).
INSERT INTO artists (name, artist_image)
SELECT DISTINCT track_artist, 'default-artist-image.png' -- placeholder
FROM spotify_import_raw
ON CONFLICT (name) DO NOTHING;

-- 4. Albums, de-duplicated by Spotify id. Year-only / year-month release dates
--    are padded so they cast cleanly to DATE.
INSERT INTO albums (spotify_id, name, release_date, album_cover)
SELECT DISTINCT
    track_album_id,
    track_album_name,
    CASE
        WHEN track_album_release_date ~ '^[0-9]{4}$'
            THEN (track_album_release_date || '-01-01')::DATE -- some data only had years, regex normalises where relevant
        WHEN track_album_release_date ~ '^[0-9]{4}-[0-9]{2}$'
            THEN (track_album_release_date || '-01')::DATE
        ELSE track_album_release_date::DATE
    END,
    'default-album-cover.png'
FROM spotify_import_raw
ON CONFLICT (spotify_id) DO NOTHING;

-- 5. Tracks. artist_id is resolved by joining the populated artists table on
--    name; album_id references albums.spotify_id loaded above.
INSERT INTO tracks (spotify_id, name, album_id, duration_ms, genre, artist_id)
SELECT
    raw.track_id,
    raw.track_name,
    raw.track_album_id,
    raw.duration_ms,
    raw.playlist_genre,
    artists.id
FROM spotify_import_raw raw
JOIN artists ON artists.name = raw.track_artist
ON CONFLICT (spotify_id) DO NOTHING;